import type { JSONSchema } from "json-schema-to-ts";
import { FromSchema } from "json-schema-to-ts";

export const WorkspaceSchema = {
  $id: "workspace.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "Workspace",
  type: "object",
  properties: {
    gemini3flash: {
      type: "object",
      properties: {
        description: { type: "string" },
      },
      additionalProperties: true,
    },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type Workspace = FromSchema<typeof WorkspaceSchema>;

export const ChannelSchema = {
  $id: "channel.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "Channel",
  type: "object",
  additionalProperties: true,
} as const satisfies JSONSchema;

export type Channel = FromSchema<typeof ChannelSchema>;

export const PostSchema = {
  $id: "post.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "Post",
  type: "object",
  required: ["msg"],
  properties: {
    msg: { type: "string" },
    parent: { type: "string" },
    reactions: {
      type: "object",
      additionalProperties: {
        type: "array",
        items: { type: "string" },
      },
    },
    extensions: {
      type: "object",
      additionalProperties: true,
    },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type Post = FromSchema<typeof PostSchema>;

// Metadata schema (OwlDB adds this to documents)
export const MetaSchema = {
  $id: "meta.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "Meta",
  type: "object",
  required: ["createdBy", "createdAt"],
  properties: {
    createdBy: { type: "string" },
    createdAt: { type: "number" },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type Meta = FromSchema<typeof MetaSchema>;

export const DocumentSchema = {
  $id: "document.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "Document",
  type: "object",
  required: ["name", "data", "meta"],
  properties: {
    name: { type: "string" },
    data: { type: "object" },
    meta: { $ref: "meta.json" },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type Document<T = any> = {
  name: string;
  data: T;
  meta: Meta;
};

export const CollectionSchema = {
  $id: "collection.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "Collection",
  type: "array",
  items: { $ref: "document.json" },
} as const satisfies JSONSchema;

export type Collection<T = any> = Document<T>[];

export const AuthResponseSchema = {
  $id: "authResponse.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "AuthResponse",
  type: "object",
  required: ["token"],
  properties: {
    token: { type: "string" },
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type AuthResponse = FromSchema<typeof AuthResponseSchema>;

import { Document, Workspace, Channel, Post } from "./schema";

export type StateListener = () => void;

class State {
  private listeners: StateListener[] = [];
  private currentUser: string | null = null;
  private currentWorkspace: Document<Workspace> | null = null;
  private currentChannel: Document<Channel> | null = null;
  private workspaces: Document<Workspace>[] = [];
  private channels: Document<Channel>[] = [];
  private posts: Document<Post>[] = [];

  subscribe(listener: StateListener) {
    this.listeners.push(listener);
    return () => {
      this.listeners = this.listeners.filter((l) => l !== listener);
    };
  }

  private notify() {
    this.listeners.forEach((l) => l());
  }

  getCurrentUser() { return this.currentUser; }
  setCurrentUser(user: string | null) {
    this.currentUser = user;
    this.notify();
  }

  getCurrentWorkspace() { return this.currentWorkspace; }
  setCurrentWorkspace(workspace: Document<Workspace> | null) {
    this.currentWorkspace = workspace;
    this.currentChannel = null;
    this.channels = [];
    this.posts = [];
    this.notify();
  }

  getCurrentChannel() { return this.currentChannel; }
  setCurrentChannel(channel: Document<Channel> | null) {
    this.currentChannel = channel;
    this.posts = [];
    this.notify();
  }

  getWorkspaces() { return this.workspaces; }
  setWorkspaces(workspaces: Document<Workspace>[]) { this.workspaces = workspaces; this.notify(); }

  getChannels() { return this.channels; }
  setChannels(channels: Document<Channel>[]) { this.channels = channels; this.notify(); }

  getPosts() { return this.posts; }
  setPosts(posts: Document<Post>[]) { this.posts = posts; this.notify(); }

  addOrUpdatePost(post: Document<Post>) {
    const index = this.posts.findIndex(p => p.name === post.name);
    if (index !== -1) {
      this.posts[index] = post;
    } else {
      this.posts.push(post);
    }
    this.notify();
  }
}

export const state = new State();

import "./components/AppRoot";

console.log("Main script starting");

