import { state } from "../state";
import { api } from "../api";
import { slog } from "../slog";

export class WorkspaceList extends HTMLElement {
  private error: string | null = null;
  private unsubscribe: (() => void) | null = null;

  constructor() {
    super();
    this.attachShadow({ mode: "open" });
  }

  connectedCallback() {
    this.unsubscribe = state.subscribe(() => this.render());
    this.loadWorkspaces();
  }

  disconnectedCallback() {
    if (this.unsubscribe) this.unsubscribe();
  }

  async loadWorkspaces() {
    try {
      const workspaces = await api.getWorkspaces();
      state.setWorkspaces(workspaces);
    } catch (e: any) {
      slog.error("Failed to load workspaces", ["error", e]);
      this.error = `Failed to load workspaces: ${e.message}`;
      this.render();
    }
  }

  async createWorkspace() {
    const input = this.shadowRoot!.getElementById("new-workspace-name") as HTMLInputElement;
    const descInput = this.shadowRoot!.getElementById("new-workspace-desc") as HTMLInputElement;
    const name = input.value.trim();
    const description = descInput.value.trim();
    if (!name) return;

    if (state.getWorkspaces().some(w => w.name === name)) {
      this.error = "Workspace already exists";
      this.render();
      return;
    }

    try {
      await api.createWorkspaceWithData(name, { gemini3flash: { description } });
      input.value = "";
      descInput.value = "";
      await this.loadWorkspaces();
      const newWorkspace = state.getWorkspaces().find(w => w.name === name);
      if (newWorkspace) {
        state.setCurrentWorkspace(newWorkspace);
      }
    } catch (e: any) {
      this.error = `Failed to create workspace: ${e.message}`;
      this.render();
    }
  }

  async deleteWorkspace(name: string) {
    try {
      await api.deleteWorkspace(name);
      state.setCurrentWorkspace(null);
      await this.loadWorkspaces();
    } catch (e: any) {
      this.error = `Failed to delete workspace: ${e.message}`;
      this.render();
    }
  }

  render() {
    const shadow = this.shadowRoot!;
    const workspaces = state.getWorkspaces();
    const currentWorkspace = state.getCurrentWorkspace();

    shadow.innerHTML = `
      <style>
        :host {
          display: block;
          padding: 1rem;
        }
        .workspace-item {
          display: flex;
          flex-direction: column;
          padding: 0.5rem;
          cursor: pointer;
          border-bottom: 1px solid #eee;
        }
        .workspace-item.active {
          background: #ddd;
          font-weight: bold;
        }
        .workspace-header {
           display: flex;
           justify-content: space-between;
           align-items: center;
        }
        .workspace-description {
           font-size: 0.8rem;
           color: #666;
           font-weight: normal;
        }
        .error {
          color: red;
          font-size: 0.8rem;
          margin-bottom: 0.5rem;
        }
        .error-close {
           cursor: pointer;
           margin-left: 0.5rem;
           font-weight: bold;
        }
      </style>
      <div id="workspace-container">
        <h3>Workspaces <button id="refresh-workspaces">🔄</button></h3>
        ${this.error ? `<div class="error">${this.error}<span class="error-close" id="close-error">X</span></div>` : ""}
        <div style="display: flex; flex-direction: column; gap: 0.2rem; margin-bottom: 1rem;">
          <input type="text" id="new-workspace-name" placeholder="New workspace" />
          <input type="text" id="new-workspace-desc" placeholder="Description (extension)" />
          <button id="create-workspace-btn">Create</button>
        </div>
        <div id="workspaces-list">
          ${workspaces.map(w => `
            <div class="workspace-item ${currentWorkspace?.name === w.name ? "active" : ""}" data-name="${w.name}">
              <div class="workspace-header">
                <span class="open-workspace">${w.name}</span>
                <button class="delete-workspace" data-name="${w.name}">Delete</button>
              </div>
              ${w.data.gemini3flash?.description ? `<div class="workspace-description">${w.data.gemini3flash.description}</div>` : ""}
            </div>
          `).join("")}
        </div>
      </div>
    `;

    shadow.getElementById("refresh-workspaces")?.addEventListener("click", () => this.loadWorkspaces());
    shadow.getElementById("create-workspace-btn")?.addEventListener("click", () => this.createWorkspace());
    shadow.getElementById("close-error")?.addEventListener("click", () => {
      this.error = null;
      this.render();
    });

    shadow.querySelectorAll(".open-workspace").forEach(el => {
      el.addEventListener("click", () => {
        const name = (el.parentElement as HTMLElement).dataset.name;
        const workspace = workspaces.find(w => w.name === name);
        if (workspace) {
          state.setCurrentWorkspace(workspace);
        } else {
           this.error = "Workspace no longer exists";
           this.render();
        }
      });
    });

    shadow.querySelectorAll(".delete-workspace").forEach(el => {
      el.addEventListener("click", (e) => {
        e.stopPropagation();
        const name = (el as HTMLElement).dataset.name!;
        this.deleteWorkspace(name);
      });
    });
  }
}

