+          display: flex;
+          flex-direction: column;
+          overflow-y: auto;
+        }
+        .content {
+          flex: 1;
+          display: flex;
+          flex-direction: column;
+          overflow: hidden;
+        }
+        button.logout {
+           background: #e74c3c;
+           color: white;
+           border: none;
+           padding: 0.5rem 1rem;
