@@ -0,0 +1,170 @@
+import { state } from "../state";
+import { api } from "../api";
+import { slog } from "../slog";
+
+export class ChannelList extends HTMLElement {
+  private error: string | null = null;
+  private unsubscribe: (() => void) | null = null;
+
+  constructor() {
+    super();
+    this.attachShadow({ mode: "open" });
+  }
+
+  connectedCallback() {
+    this.unsubscribe = state.subscribe(() => {
+        // If workspace changed, we might need to load channels
+        this.render();
+    });
+    this.loadChannels();
+  }
+
+  disconnectedCallback() {
+    if (this.unsubscribe) this.unsubscribe();
+  }
+
+  async loadChannels() {
+    const workspace = state.getCurrentWorkspace();
+    if (!workspace) return;
+
+    try {
+      const channels = await api.getChannels(workspace.name);
+      state.setChannels(channels);
+    } catch (e: any) {
+      slog.error("Failed to load channels", ["error", e]);
+      this.error = `Failed to load channels: ${e.message}`;
+      this.render();
+    }
+  }
+
+  async createChannel() {
+    const workspace = state.getCurrentWorkspace();
+    if (!workspace) return;
+
+    const input = this.shadowRoot!.getElementById("new-channel-name") as HTMLInputElement;
+    const name = input.value.trim();
+    if (!name) return;
+
+    if (state.getChannels().some(c => c.name === name)) {
+      this.error = "Channel already exists";
+      this.render();
+      return;
+    }
+
+    try {
+      await api.createChannel(workspace.name, name);
+      input.value = "";
+      await this.loadChannels();
+      const newChannel = state.getChannels().find(c => c.name === name);
+      if (newChannel) {
+        state.setCurrentChannel(newChannel);
+      }
+    } catch (e: any) {
+      this.error = `Failed to create channel: ${e.message}`;
+      this.render();
+    }
+  }
+
+  async deleteChannel(name: string) {
+    const workspace = state.getCurrentWorkspace();
+    if (!workspace) return;
+
+    try {
+      await api.deleteChannel(workspace.name, name);
+      if (state.getCurrentChannel()?.name === name) {
+        state.setCurrentChannel(null);
+      }
+      await this.loadChannels();
+    } catch (e: any) {
+      this.error = `Failed to delete channel: ${e.message}`;
+      this.render();
+    }
+  }
+
+  render() {
+    const shadow = this.shadowRoot!;
+    const channels = state.getChannels();
+    const currentChannel = state.getCurrentChannel();
+    const workspace = state.getCurrentWorkspace();
+
+    if (!workspace) {
+        shadow.innerHTML = "";
+        return;
+    }
+
+    shadow.innerHTML = `
+      <style>
+        :host {
+          display: block;
+          padding: 1rem;
+        }
+        .channel-item {
+          display: flex;
+          justify-content: space-between;
+          padding: 0.5rem;
+          cursor: pointer;
+        }
+        .channel-item.active {
+          background: #ddd;
+          font-weight: bold;
+        }
+        .error {
+          color: red;
+          font-size: 0.8rem;
+          margin-bottom: 0.5rem;
+        }
+        .error-close {
+           cursor: pointer;
+           margin-left: 0.5rem;
+           font-weight: bold;
+        }
+      </style>
+      <div id="channel-container">
+        <h3>Channels in ${workspace.name} <button id="refresh-channels">🔄</button></h3>
+        ${this.error ? `<div class="error">${this.error}<span class="error-close" id="close-error">X</span></div>` : ""}
+        <div>
+          <input type="text" id="new-channel-name" placeholder="New channel" />
+          <button id="create-channel-btn">Create</button>
+        </div>
+        <div id="channels-list">
+          ${channels.map(c => `
+            <div class="channel-item ${currentChannel?.name === c.name ? "active" : ""}" data-name="${c.name}">
+              <span class="open-channel">${c.name}</span>
+              <button class="delete-channel" data-name="${c.name}">Delete</button>
+            </div>
+          `).join("")}
+        </div>
+      </div>
+    `;
+
+    shadow.getElementById("refresh-channels")?.addEventListener("click", () => this.loadChannels());
+    shadow.getElementById("create-channel-btn")?.addEventListener("click", () => this.createChannel());
+    shadow.getElementById("close-error")?.addEventListener("click", () => {
+      this.error = null;
+      this.render();
+    });
+
+    shadow.querySelectorAll(".open-channel").forEach(el => {
+      el.addEventListener("click", () => {
+        const name = (el.parentElement as HTMLElement).dataset.name;
+        const channel = channels.find(c => c.name === name);
+        if (channel) {
+          state.setCurrentChannel(channel);
+        } else {
+            this.error = "Channel no longer exists";
+            this.render();
+        }
+      });
+    });
+
+    shadow.querySelectorAll(".delete-channel").forEach(el => {
+      el.addEventListener("click", (e) => {
+        e.stopPropagation();
+        const name = (el as HTMLElement).dataset.name!;
+        this.deleteChannel(name);
+      });
+    });
+  }
+}
+
+customElements.define("channel-list", ChannelList);
